	@Test
	void oneGateEvaluatesAndMovesOnlyAtDrainedPrefix() throws Exception {
		AtomicInteger evaluations = new AtomicInteger();
		NativeBooleanFilter target = row -> {
			evaluations.incrementAndGet();
			return true;
		};
		AdaptiveFilterMetadata metadata = AdaptiveFilterMetadata.eligible(41, 4).withRequiredMask(1L);
		FilterPlacementEnvelope envelope = new FilterPlacementEnvelope(41, new int[] { 0, 1, 2 });
		Class<?> sessionType = Class
				.forName("org.eclipse.rdf4j.sail.lmdb.evaluation.AdaptiveFilterSession");
		Object session = sessionType
				.getDeclaredConstructor(NativeBooleanFilter.class, AdaptiveFilterMetadata.class,
						FilterPlacementEnvelope.class)
				.newInstance(target, metadata, envelope);
		Class<?> gateType = Class
				.forName("org.eclipse.rdf4j.sail.lmdb.evaluation.AdaptiveFilterGateCursor");
		Constructor<?> gateConstructor = gateType.getDeclaredConstructor(RowCursor.class, RowState.class, sessionType,
				int.class);
		RowCursor earliestGate = (RowCursor) gateConstructor.newInstance(new CountCursor(2), null, session, 0);
		RowCursor deepestGate = (RowCursor) gateConstructor.newInstance(earliestGate, null, session, 2);
		Class<?> boundaryType = Class
				.forName("org.eclipse.rdf4j.sail.lmdb.evaluation.AdaptivePrefixBoundaryCursor");
		RowCursor boundary = (RowCursor) boundaryType.getDeclaredConstructor(RowCursor.class, sessionType)
				.newInstance(deepestGate, session);

		assertThat(boundary.next()).isTrue();
		assertThat(evaluations).hasValue(1);
		sessionType.getDeclaredMethod("requestMove", int.class).invoke(session, 0);
		assertThat(activeDepth(session)).isEqualTo(2);
		assertThat(boundary.next()).isTrue();
		assertThat(activeDepth(session)).isZero();
		assertThat(evaluations).hasValue(2);
		assertThat(boundary.next()).isFalse();
		assertThat(longField(session, "completedPrefixes")).isEqualTo(2L);
		assertThat((long[]) field(session, "arrivalsByCandidate")).containsExactly(2L, 0L, 2L);
		assertThat((long[]) field(session, "evaluationsByCandidate")).containsExactly(1L, 0L, 1L);
	}

