	@Test
	void outwardTrialRollsBackAndDoublesOnlyOnDepthChanges() throws Exception {
		AlternatingFilter filter = new AlternatingFilter();
		AdaptiveFilterSession session = policySession(filter);

		drive(session, 1, 4, 16, 100L, 1_024);

		assertThat(session.placement.activeDepth()).isZero();
		assertThat(longField(session, "interval")).isEqualTo(2_048L);
		assertThat(longField(session, "moves")).isOne();

		drive(session, 1, 4, 16, 500L, 128);

		assertThat(session.placement.activeDepth()).isEqualTo(2);
		assertThat(longField(session, "interval")).isEqualTo(4_096L);
		assertThat(longField(session, "rollbacks")).isOne();
		assertThat(longField(session, "commits")).isZero();
		assertThat(((long[]) field(session, "blacklistUntil"))[0]).isGreaterThan(session.completedPrefixes);
		assertThat(longField(session, "cooldownUntil"))
				.isEqualTo(session.completedPrefixes + longField(session, "interval"));
	}

	@Test
	void commitKeepsIntervalThenInwardShiftRollsBack() throws Exception {
		AlternatingFilter filter = new AlternatingFilter();
		AdaptiveFilterSession session = policySession(filter);

		drive(session, 1, 4, 16, 500L, 1_024);
		assertThat(session.placement.activeDepth()).isZero();
		drive(session, 1, 4, 16, 10L, 2_048);

		assertThat(session.commits).isOne();
		assertThat(session.interval).isEqualTo(2_048L);
		assertThat(session.placement.activeDepth()).isZero();

		filter.passAll = true;
		drive(session, 16, 8, 2, 100L, 2_048);
		assertThat(session.placement.activeDepth()).as("the entire first window is cooldown").isZero();
		drive(session, 16, 8, 2, 100L, 2_048);

		assertThat(session.placement.activeDepth()).isEqualTo(2);
		assertThat(session.interval).isEqualTo(4_096L);

		drive(session, 1, 4, 64, 5_000L, 128);
		assertThat(session.placement.activeDepth()).isZero();
		assertThat(session.rollbacks).isOne();
		assertThat(session.interval).isEqualTo(8_192L);
	}

	@Test
	void setupFailureClosesWholeBorrowedBagAndSuppressesFeedback() {
		IllegalStateException setupFailure = new IllegalStateException("synthetic adaptive setup failure");
		TrackingStatistics statistics = new TrackingStatistics();
		TrackingFilter targetDelegate = new TrackingFilter(null);
		TrackingFilter fixedDelegate = new TrackingFilter(null);
		Filter targetNode = new Filter(new SingletonSet(),
				new Compare(new Var("left"), new Var("right"), Compare.CompareOp.EQ));
		Filter fixedNode = new Filter(new SingletonSet(),
				new Compare(new Var("left"), new Var("right"), Compare.CompareOp.EQ));
		AdaptiveFilterMetadata metadata = AdaptiveFilterMetadata.eligible(71, 4);
		RecordingNativeBooleanFilter target = new RecordingNativeBooleanFilter(targetDelegate, targetNode, statistics,
				metadata);
		RecordingNativeBooleanFilter fixed = new RecordingNativeBooleanFilter(fixedDelegate, fixedNode, statistics);
		MultiJoinPlan plan = new MultiJoinPlan(
				new SlotPlan[] { new SetupFailurePlan(1L, 4_096.0d, setupFailure), values(1, 25) },
				new MaskedFilter[] { new MaskedFilter(target, 1L, metadata), new MaskedFilter(fixed, 1L << 1) });
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("left", 0, "right", 1), null);
		layout.freeze(List.of("left", "right"));
		NativeRowsStep step = step(plan, layout);
		String previous = System.getProperty(LmdbNativeAdaptiveFilterPlacement.ENABLED_PROPERTY);
		System.setProperty(LmdbNativeAdaptiveFilterPlacement.ENABLED_PROPERTY, "true");
		try {
			assertThatThrownBy(() -> LmdbNativeAdaptiveFilterPlacement.tryOpen(step, plan, row(layout)))
					.isSameAs(setupFailure);
		} finally {
			restoreAdaptiveProperty(previous);
		}

		assertThat(statistics.outcomeCalls).isZero();
		assertThat(targetDelegate.closeCalls).isOne();
		assertThat(fixedDelegate.closeCalls).as("the suppressing lease owns the complete admitted bag").isOne();
	}

