	@Test
	void adaptiveDispatchRemainsTheFinalFallbackWhenEnabled() throws Exception {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("left", 0, "right", 1), null);
		layout.freeze(List.of("left", "right"));
		MultiJoinPlan plan = admittedPlan();
		NativeRowsStep step = step(plan, layout);
		Method initialize = NativeRowsIteration.class.getDeclaredMethod("initialize");
		initialize.setAccessible(true);
		String adaptive = System.getProperty(LmdbNativeAdaptiveFilterPlacement.ENABLED_PROPERTY);
		String batch = System.getProperty(NativeBatch.ENABLED_PROPERTY);
		String parallel = System.getProperty("rdf4j.lmdb.parallel.enabled");
		System.setProperty(NativeBatch.ENABLED_PROPERTY, "true");
		System.setProperty("rdf4j.lmdb.parallel.enabled", "false");
		try {
			System.setProperty(LmdbNativeAdaptiveFilterPlacement.ENABLED_PROPERTY, "true");
			NativeRowsIteration enabled = new NativeRowsIteration(step, EmptyBindingSet.getInstance());
			assertThat(initialize.invoke(enabled)).isEqualTo(true);
			assertThat(enabled.cursor).isInstanceOf(AdaptiveOwningCursor.class);
			enabled.close();

			System.setProperty(LmdbNativeAdaptiveFilterPlacement.ENABLED_PROPERTY, "false");
			NativeRowsIteration disabled = new NativeRowsIteration(step(admittedPlan(), layout),
					EmptyBindingSet.getInstance());
			assertThat(initialize.invoke(disabled)).isEqualTo(true);
			assertThat(disabled.cursor).isNotInstanceOf(AdaptiveOwningCursor.class);
			disabled.close();
		} finally {
			restoreProperty(LmdbNativeAdaptiveFilterPlacement.ENABLED_PROPERTY, adaptive);
			restoreProperty(NativeBatch.ENABLED_PROPERTY, batch);
			restoreProperty("rdf4j.lmdb.parallel.enabled", parallel);
		}
	}

